namespace sv_e2345d9076aa4ccc9b59d8c2fb917827.Client.Models;

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTime EstimatedDelivery,
    List<StatusUpdate> Updates);

public record StatusUpdate(DateTime Timestamp, string Description, string Location);

using sv_e2345d9076aa4ccc9b59d8c2fb917827.Client.Models;

namespace sv_e2345d9076aa4ccc9b59d8c2fb917827.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_e2345d9076aa4ccc9b59d8c2fb917827.Client.Models;
using sv_e2345d9076aa4ccc9b59d8c2fb917827.Client.Services;

namespace sv_e2345d9076aa4ccc9b59d8c2fb917827.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new()
    {
        ["PKG-001"] = new ShipmentDetails(
            "PKG-001",
            "In Transit",
            "Chicago, IL",
            new DateTime(2026, 5, 25),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 20, 8, 0, 0), "Package picked up", "New York, NY"),
                new(new DateTime(2026, 5, 21, 14, 30, 0), "Arrived at sorting facility", "Philadelphia, PA"),
                new(new DateTime(2026, 5, 22, 9, 15, 0), "In transit to destination", "Chicago, IL")
            }),
        ["PKG-002"] = new ShipmentDetails(
            "PKG-002",
            "Delivered",
            "San Francisco, CA",
            new DateTime(2026, 5, 20),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 17, 10, 0, 0), "Package picked up", "Seattle, WA"),
                new(new DateTime(2026, 5, 18, 16, 45, 0), "Arrived at sorting facility", "Portland, OR"),
                new(new DateTime(2026, 5, 19, 11, 0, 0), "Out for delivery", "San Francisco, CA"),
                new(new DateTime(2026, 5, 19, 14, 22, 0), "Delivered", "San Francisco, CA")
            }),
        ["PKG-003"] = new ShipmentDetails(
            "PKG-003",
            "Processing",
            "Dallas, TX",
            new DateTime(2026, 5, 28),
            new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 22, 7, 0, 0), "Label created", "Dallas, TX")
            })
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_e2345d9076aa4ccc9b59d8c2fb917827.Client.Models
@using sv_e2345d9076aa4ccc9b59d8c2fb917827.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-message">
        <p>@_errorMessage</p>
        <button @onclick="Retry">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToShortDateString()</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.Updates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> —
                    @update.Description (@update.Location)
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task Retry()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

